        /// <returns><see cref="Task"/>&lt;<see cref="IAnswerTransactionRequestChallengeApiResponse"/>?&gt;</returns>
        Task<IAnswerTransactionRequestChallengeApiResponse?> AnswerTransactionRequestChallengeOrDefaultAsync(string bankid, string accountid, string viewid, string transactionrequesttype, string transactionrequestid, AnswerTransactionRequestChallengeRequest answerTransactionRequestChallengeRequest, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
        /// Create Transaction Request (ACCOUNT)
        /// </summary>
        /// <remarks>
