        partial void FormatAnswerTransactionRequestChallenge(ref string bankid, ref string accountid, ref string viewid, ref string transactionrequesttype, ref string transactionrequestid, AnswerTransactionRequestChallengeRequest answerTransactionRequestChallengeRequest);

