        /// <returns></returns>
        private void ValidateAnswerTransactionRequestChallenge(string bankid, string accountid, string viewid, string transactionrequesttype, string transactionrequestid, AnswerTransactionRequestChallengeRequest answerTransactionRequestChallengeRequest)
        {
            if (bankid == null)
                throw new ArgumentNullException(nameof(bankid));

            if (accountid == null)
                throw new ArgumentNullException(nameof(accountid));

            if (viewid == null)
                throw new ArgumentNullException(nameof(viewid));

            if (transactionrequesttype == null)
                throw new ArgumentNullException(nameof(transactionrequesttype));

            if (transactionrequestid == null)
                throw new ArgumentNullException(nameof(transactionrequestid));

            if (answerTransactionRequestChallengeRequest == null)
                throw new ArgumentNullException(nameof(answerTransactionRequestChallengeRequest));
        }

