        private void OnErrorAnswerTransactionRequestChallengeDefaultImplementation(Exception exceptionLocalVar, string pathFormatLocalVar, string pathLocalVar, string bankid, string accountid, string viewid, string transactionrequesttype, string transactionrequestid, AnswerTransactionRequestChallengeRequest answerTransactionRequestChallengeRequest)
