        /// <exception cref="ApiException">Thrown when fails to make API call</exception>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="account">The ACCOUNT identifier</param>
        /// <param name="createTransactionRequestAccountRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestAccountApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestAccountApiResponse> CreateTransactionRequestAccountAsync(string bankid, string accountid, string viewid, string account, CreateTransactionRequestAccountRequest createTransactionRequestAccountRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            UriBuilder uriBuilderLocalVar = new UriBuilder();

            try
            {
                ValidateCreateTransactionRequestAccount(bankid, accountid, viewid, account, createTransactionRequestAccountRequest);

                FormatCreateTransactionRequestAccount(ref bankid, ref accountid, ref viewid, ref account, createTransactionRequestAccountRequest);

