        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="cardano">The CARDANO identifier</param>
        /// <param name="createTransactionRequestCardanoRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestCardanoApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestCardanoApiResponse?> CreateTransactionRequestCardanoOrDefaultAsync(string bankid, string accountid, string cardano, CreateTransactionRequestCardanoRequest createTransactionRequestCardanoRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestCardanoAsync(bankid, accountid, cardano, createTransactionRequestCardanoRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

