        public async Task<ICreateTransactionRequestHoldApiResponse?> CreateTransactionRequestHoldOrDefaultAsync(string bankid, string accountid, string hold, CreateTransactionRequestFreeFormRequest createTransactionRequestFreeFormRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
