        public async Task<ICreateTransactionRequestSepaApiResponse?> CreateTransactionRequestSepaOrDefaultAsync(string bankid, string accountid, string viewid, string sepa, CreateTransactionRequestSepaRequest createTransactionRequestSepaRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestSepaAsync(bankid, accountid, viewid, sepa, createTransactionRequestSepaRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
