        /// <param name="viewid"></param>
        /// <param name="transactionrequestid"></param>
        private void OnErrorGetTransactionRequestDefaultImplementation(Exception exceptionLocalVar, string pathFormatLocalVar, string pathLocalVar, string bankid, string accountid, string viewid, string transactionrequestid)
        {
            bool suppressDefaultLogLocalVar = false;
            OnErrorGetTransactionRequest(ref suppressDefaultLogLocalVar, exceptionLocalVar, pathFormatLocalVar, pathLocalVar, bankid, accountid, viewid, transactionrequestid);
            if (!suppressDefaultLogLocalVar)
                Logger.LogError(exceptionLocalVar, "An error occurred while sending the request to the server.");
