        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="transactionrequestid">The TRANSACTIONREQUESTID identifier</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IGetTransactionRequestApiResponse"/>&gt;</returns>
        public async Task<IGetTransactionRequestApiResponse?> GetTransactionRequestOrDefaultAsync(string bankid, string accountid, string viewid, string transactionrequestid, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await GetTransactionRequestAsync(bankid, accountid, viewid, transactionrequestid, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

